def fix_content(filepath, proper_content):
    """Fix content field in a JSON file."""
    try:
        with open(filepath, 'r', encoding='utf-8') as f:
            data = json.load(f)
        
        # Fix content field
        data['content'] = proper_content
        
        # Write back
        with open(filepath, 'w', encoding='utf-8') as f:
            json.dump(data, f, ensure_ascii=False, indent=2)
        
        return True
    except Exception as e:
        print(f"Error: {e}")
        return False

def main():
    directory = Path('data/staffing-recruitment-agency-tools')
    
    print("Fixing content fields with proper translations...\n")
    
    fixed_count = 0
    for filename, content in content_fixes.items():
        filepath = directory / filename
        if filepath.exists():
            if fix_content(filepath, content):
                print(f"✓ Fixed content in {filename}")
                fixed_count += 1
    
    print(f"\nFixed {fixed_count} content fields")
    print("Note: Content field translations completed for key files")
    print("Remaining files have proper metadata but need content field review")

if __name__ == '__main__':
    main()
